module.exports = /*#__PURE__*/JSON.parse('{"translations":{"krv":{"label":"개역한글","note":"성경전서 개역한글판 (대한성서공회, 1961). 라이선스: 대한성서공회 공식 저작권 FAQ에 따라 저작재산권 보호기간 50년 경과로 저작권료 지급 없이 사용 가능 공공저작물 (개역개정판은 해당 없음). 데이터 출처: scrollmapper/bible_databases (GitHub, 2025-languages branch, sources/ko/KorRV/KorRV.json, License: Public Domain)."},"kids":{"label":"쉬운말","note":"쉬운말 번역 준비 중입니다."}},"chapters":[{"chapter":1,"title":"데살로니가 교회의 믿음","verses":{"krv":[{"n":1,"t":"바울과 실루아노와 디모데는 하나님 아버지와 주 예수 그리스도 안에 있는 데살로니가인의 교회에 편지하노니 은혜와 평강이 너희에게 있을지어다"},{"n":2,"t":"우리가 너희 무리를 인하여 항상 하나님께 감사하고 기도할 때에 너희를 말함은"},{"n":3,"t":"너희의 믿음의 역사와 사랑의 수고와 우리 주 예수 그리스도에 대한 소망의 인내를 우리 하나님 아버지 앞에서 쉬지 않고 기억함이니"},{"n":4,"t":"하나님의 사랑하심을 받은 형제들아 너희를 택하심을 아노라"},{"n":5,"t":"이는 우리 복음이 말로만 너희에게 이른 것이 아니라 오직 능력과 성령과 큰 확신으로 된 것이니 우리가 너희 가운데서 너희를 위하여 어떠한 사람이 된 것은 너희 아는 바와 같으니라"},{"n":6,"t":"또 너희는 많은 환난 가운데서 성령의 기쁨으로 도를 받아 우리와 주를 본받은 자가 되었으니"},{"n":7,"t":"그러므로 너희가 마게도냐와 아가야 모든 믿는 자의 본이 되었는지라"},{"n":8,"t":"주의 말씀이 너희에게로부터 마게도냐와 아가야에만 들릴 뿐 아니라 하나님을 향하는 너희 믿음의 소문이 각처에 퍼지므로 우리는 아무 말도 할 것이 없노라"},{"n":9,"t":"저희가 우리에 대하여 스스로 고하기를 우리가 어떻게 너희 가운데 들어간 것과 너희가 어떻게 우상을 버리고 하나님께로 돌아와서 사시고 참되신 하나님을 섬기며"},{"n":10,"t":"또 죽은 자들 가운데서 다시 살리신 그의 아들이 하늘로부터 강림하심을 기다린다고 말하니 이는 장래 노하심에서 우리를 건지시는 예수시니라"}],"kids":[{"n":1,"t":"바울과 실루아노와 디모데가, 하나님 아버지와 주 예수 그리스도 안에 있는 데살로니가 사람들의 교회에 편지를 써요. 은혜와 평강(평안)이 여러분에게 함께하기를 빌어요."},{"n":2,"t":"우리는 여러분 모두에 대해 늘 하나님께 감사드리고, 기도할 때마다 여러분을 말씀드려요."},{"n":3,"t":"우리는 우리 하나님 아버지 앞에서, 여러분의 믿음의 행함과 사랑의 수고와 우리 주 예수 그리스도에 대한 소망의 인내를 쉬지 않고 기억하고 있어요."},{"n":4,"t":"하나님의 사랑을 받은 형제 여러분, 우리는 하나님께서 여러분을 택하셨다는 것을 알아요."},{"n":5,"t":"우리가 전한 복음이 여러분에게 말로만 전해진 것이 아니라, 능력과 성령과 큰 확신과 함께 전해졌기 때문이에요. 우리가 여러분 가운데서 여러분을 위해 어떤 사람이 되었는지는 여러분도 잘 알지요."},{"n":6,"t":"또 여러분은 많은 환난 가운데서도 성령께서 주시는 기쁨으로 그 말씀을 받아들여서, 우리와 주님을 본받는 사람이 되었어요."},{"n":7,"t":"그래서 여러분은 마게도냐와 아가야에 있는 모든 믿는 사람들의 본이 되었어요."},{"n":8,"t":"주님의 말씀이 여러분에게서부터 마게도냐와 아가야에만 들린 것이 아니라, 하나님을 향한 여러분의 믿음의 소문이 모든 곳에 퍼져 나갔어요. 그래서 우리가 따로 무슨 말을 할 필요도 없을 정도예요."},{"n":9,"t":"그곳 사람들이 우리가 여러분 가운데 어떻게 들어가게 됐는지, 또 여러분이 어떻게 우상을 버리고 하나님께로 돌아와 살아 계시고 참되신 하나님을 섬기게 됐는지를 우리에게 직접 이야기해 주고 있어요."},{"n":10,"t":"또 죽은 사람들 가운데서 하나님이 다시 살리신 그분의 아들이 하늘로부터 오시기를 여러분이 기다리고 있다고도 말해요. 이 아들이 바로 앞으로 있을 진노에서 우리를 건져 주시는 예수님이세요."}]}},{"chapter":2,"title":"어머니와 아버지 같은 사역","verses":{"krv":[{"n":1,"t":"형제들아 우리가 너희 가운데 들어감이 헛되지 않은 줄을 너희가 친히 아나니"},{"n":2,"t":"너희 아는 바와 같이 우리가 먼저 빌립보에서 고난과 능욕을 당하였으나 우리 하나님을 힘입어 많은 싸움 중에 하나님의 복음을 너희에게 말하였노라"},{"n":3,"t":"우리의 권면은 간사에서나 부정에서 난 것도 아니요 궤계에 있는 것도 아니라"},{"n":4,"t":"오직 하나님의 옳게 여기심을 입어 복음 전할 부탁을 받았으니 우리가 이와 같이 말함은 사람을 기쁘게 하려 함이 아니요 오직 우리 마음을 감찰하시는 하나님을 기쁘시게 하려 함이라"},{"n":5,"t":"너희도 알거니와 우리가 아무 때에도 아첨의 말이나 탐심의 탈을 쓰지 아니한 것을 하나님이 증거하시느니라"},{"n":6,"t":"우리가 그리스도의 사도로 능히 존중할 터이나 그러나 너희에게든지 다른 이에게든지 사람에게는 영광을 구치 아니하고"},{"n":7,"t":"오직 우리가 너희 가운데서 유순한 자 되어 유모가 자기 자녀를 기름과 같이 하였으니"},{"n":8,"t":"우리가 이같이 너희를 사모하여 하나님의 복음으로만 아니라 우리 목숨까지 너희에게 주기를 즐겨함은 너희가 우리의 사랑하는 자 됨이니라"},{"n":9,"t":"형제들아 우리의 수고와 애쓴 것을 너희가 기억하리니 너희 아무에게도 누를 끼치지 아니하려고 밤과 낮으로 일하면서 너희에게 하나님의 복음을 전파하였노라"},{"n":10,"t":"우리가 너희 믿는 자들을 향하여 어떻게 거룩하고 옳고 흠 없이 행한 것에 대하여 너희가 증인이요 하나님도 그러하시도다"},{"n":11,"t":"너희도 아는 바와 같이 우리가 너희 각 사람에게 아비가 자기 자녀에게 하듯 권면하고 위로하고 경계하노니"},{"n":12,"t":"이는 너희를 부르사 자기 나라와 영광에 이르게 하시는 하나님께 합당히 행하게 하려 함이니라"},{"n":13,"t":"이러므로 우리가 하나님께 쉬지 않고 감사함은 너희가 우리에게 들은 바 하나님의 말씀을 받을 때에 사람의 말로 아니하고 하나님의 말씀으로 받음이니 진실로 그러하다 이 말씀이 또한 너희 믿는 자 속에서 역사하느니라"},{"n":14,"t":"형제들아 너희가 그리스도 예수 안에서 유대에 있는 하나님의 교회들을 본받은 자 되었으니 저희가 유대인들에게 고난을 받음과 같이 너희도 너희 나라 사람들에게 동일한 것을 받았느니라"},{"n":15,"t":"유대인은 주 예수와 선지자들을 죽이고 우리를 쫓아내고 하나님을 기쁘시게 아니하고 모든 사람에게 대적이 되어"},{"n":16,"t":"우리가 이방인에게 말하여 구원 얻게 함을 저희가 금하여 자기 죄를 항상 채우매 노하심이 끝까지 저희에게 임하였느니라"},{"n":17,"t":"형제들아 우리가 잠시 너희를 떠난 것은 얼굴이요 마음은 아니니 너희 얼굴 보기를 열정으로 더욱 힘썼노라"},{"n":18,"t":"그러므로 나 바울은 한 번 두 번 너희에게 가고자 하였으나 사단이 우리를 막았도다"},{"n":19,"t":"우리의 소망이나 기쁨이나 자랑의 면류관이 무엇이냐 그의 강림하실 때 우리 주 예수 앞에 너희가 아니냐"},{"n":20,"t":"너희는 우리의 영광이요 기쁨이니라"}],"kids":[{"n":1,"t":"형제 여러분, 우리가 여러분 가운데 들어간 것이 헛되지 않았다는 것을 여러분 자신이 잘 알지요."},{"n":2,"t":"여러분도 아는 것처럼, 우리는 먼저 빌립보에서 고난을 당하고 모욕도 받았어요. 그러나 우리 하나님께 힘을 얻어, 많은 반대 속에서도 하나님의 복음을 여러분에게 담대하게 전했어요."},{"n":3,"t":"우리가 권면하는 것은 잘못된 생각에서 나온 것도 아니고, 더러운 동기에서 나온 것도 아니며, 속임수도 아니에요."},{"n":4,"t":"오직 우리는 하나님께 인정받아 복음을 전하라는 사명을 맡았기 때문에 그렇게 말하는 거예요. 우리는 사람을 기쁘게 하려는 게 아니라, 우리 마음을 살피시는 하나님을 기쁘시게 해 드리려는 거예요."},{"n":5,"t":"여러분도 알다시피 우리는 어느 때에도 아첨하는 말을 쓰지 않았고, 욕심을 감추는 가면을 쓰지도 않았어요. 이건 하나님께서 증인이세요."},{"n":6,"t":"우리가 그리스도의 사도로서 권위를 내세울 수도 있었지만, 여러분에게서든 다른 사람에게서든 사람에게서 영광을 구하지 않았어요."},{"n":7,"t":"오직 우리는 여러분 가운데서 부드럽게 행동했어요. 마치 유모가 자기 어린아이를 돌보는 것처럼요."},{"n":8,"t":"우리는 여러분을 이렇게 사랑해서, 하나님의 복음만이 아니라 우리 목숨까지도 여러분에게 기꺼이 내주려고 했어요. 여러분이 우리의 사랑하는 사람들이 되었기 때문이에요."},{"n":9,"t":"형제 여러분, 우리의 수고와 애씀을 여러분도 기억하지요. 우리는 여러분 누구에게도 짐이 되지 않으려고 밤낮으로 일하면서 여러분에게 하나님의 복음을 전했어요."},{"n":10,"t":"우리가 여러분 믿는 사람들에게 얼마나 거룩하고 옳고 흠 없이 행했는지, 여러분이 증인이고 하나님도 증인이세요."},{"n":11,"t":"여러분도 알다시피, 우리는 여러분 한 사람 한 사람에게 아버지가 자기 자녀에게 하듯이 권면하고 위로하고 권고했어요."},{"n":12,"t":"이것은 여러분을 자기 나라와 영광으로 부르시는 하나님께 어울리게 살아가게 하려는 거예요."},{"n":13,"t":"그래서 우리는 쉬지 않고 하나님께 감사드려요. 여러분이 우리에게 들은 하나님의 말씀을 받을 때에 사람의 말로 받은 것이 아니라 (실제로 그러한 것처럼) 하나님의 말씀으로 받았기 때문이에요. 이 말씀이 믿는 여러분 안에서 일하고 있어요."},{"n":14,"t":"형제 여러분, 여러분은 그리스도 예수님 안에서 유대 지방에 있는 하나님의 교회들을 본받는 사람들이 되었어요. 그들이 유대 사람들에게 고난받은 것처럼, 여러분도 같은 동족 사람들에게 똑같은 고난을 받았어요."},{"n":15,"t":"그 유대 사람들은 주 예수님과 예언자들을 죽였고, 우리를 핍박해서 쫓아냈으며, 하나님을 기쁘시게 하지 않고, 모든 사람에게 적대적이에요."},{"n":16,"t":"또 우리가 이방 사람들에게 말씀을 전해서 구원받게 하는 것을 막고 있어요. 그렇게 자기 죄를 늘 가득 채워 가고 있고, 결국 진노가 끝까지 그들에게 닥쳤어요."},{"n":17,"t":"형제 여러분, 우리가 여러분에게서 잠시 떨어져 있는 것은 얼굴만 떨어진 것이지 마음까지 떨어진 게 아니에요. 우리는 여러분의 얼굴을 다시 보고 싶어서 더욱 간절히 애를 썼어요."},{"n":18,"t":"그래서 나 바울은 한 번도 아니고 두 번이나 여러분에게 가려고 했어요. 그런데 사탄이 우리를 막았어요."},{"n":19,"t":"우리의 소망이나 기쁨이나 자랑의 면류관이 무엇일까요? 우리 주 예수님이 다시 오실 때 그분 앞에 서 있을 여러분이 아니겠어요?"},{"n":20,"t":"여러분이 바로 우리의 영광이고 기쁨이에요."}]}},{"chapter":3,"title":"디모데의 보고","verses":{"krv":[{"n":1,"t":"이러므로 우리가 참다 못하여 우리만 아덴에 머물기를 좋게 여겨"},{"n":2,"t":"우리 형제 곧 그리스도 복음의 하나님의 일꾼인 디모데를 보내노니 이는 너희를 굳게 하고 너희 믿음에 대하여 위로함으로"},{"n":3,"t":"누구든지 이 여러 환난 중에 요동치 않게 하려 함이라 우리로 이것을 당하게 세우신 줄을 너희가 친히 알리라"},{"n":4,"t":"우리가 너희와 함께 있을 때에 장차 받을 환난을 너희에게 미리 말하였더니 과연 그렇게 된 것을 너희가 아느니라"},{"n":5,"t":"이러므로 나도 참다 못하여 너희 믿음을 알기 위하여 보내었노니 이는 혹 시험하는 자가 너희를 시험하여 우리 수고를 헛되게 할까 함일러니"},{"n":6,"t":"지금은 디모데가 너희에게로부터 와서 너희 믿음과 사랑의 기쁜 소식을 우리에게 전하고 또 너희가 항상 우리를 잘 생각하여 우리가 너희를 간절히 보고자 함과 같이 너희도 우리를 간절히 보고자 한다 하니"},{"n":7,"t":"이러므로 형제들아 우리가 모든 궁핍과 환난 가운데서 너희 믿음으로 말미암아 너희에게 위로를 받았노라"},{"n":8,"t":"그러므로 너희가 주 안에 굳게 선즉 우리가 이제는 살리라"},{"n":9,"t":"우리가 우리 하나님 앞에서 너희를 인하여 모든 기쁨으로 기뻐하니 너희를 위하여 능히 어떠한 감사함으로 하나님께 보답할꼬"},{"n":10,"t":"주야로 심히 간구함은 너희 얼굴을 보고 너희 믿음의 부족함을 온전케 하려 함이라"},{"n":11,"t":"하나님 우리 아버지와 우리 주 예수는 우리 길을 너희에게로 직행하게 하옵시며"},{"n":12,"t":"또 주께서 우리가 너희를 사랑함과 같이 너희도 피차간과 모든 사람에 대한 사랑이 더욱 많아 넘치게 하사"},{"n":13,"t":"너희 마음을 굳게 하시고 우리 주 예수께서 그의 모든 성도와 함께 강림하실 때에 하나님 우리 아버지 앞에서 거룩함에 흠이 없게 하시기를 원하노라"}],"kids":[]}},{"chapter":4,"title":"주의 강림을 기다림","verses":{"krv":[{"n":1,"t":"종말로 형제들아 우리가 주 예수 안에서 너희에게 구하고 권면하노니 너희가 마땅히 어떻게 행하며 하나님께 기쁘시게 할 것을 우리에게 받았으니 곧 너희 행하는 바라 더욱 많이 힘쓰라"},{"n":2,"t":"우리가 주 예수로 말미암아 너희에게 무슨 명령으로 준 것을 너희가 아느니라"},{"n":3,"t":"하나님의 뜻은 이것이니 너희의 거룩함이라 곧 음란을 버리고"},{"n":4,"t":"각각 거룩함과 존귀함으로 자기의 아내 취할 줄을 알고"},{"n":5,"t":"하나님을 모르는 이방인과 같이 색욕을 좇지 말고"},{"n":6,"t":"이 일에 분수를 넘어서 형제를 해하지 말라 이는 우리가 너희에게 미리 말하고 증거한 것과 같이 이 모든 일에 주께서 신원하여 주심이니라"},{"n":7,"t":"하나님이 우리를 부르심은 부정케 하심이 아니요 거룩케 하심이니"},{"n":8,"t":"그러므로 저버리는 자는 사람을 저버림이 아니요 너희에게 그의 성령을 주신 하나님을 저버림이니라"},{"n":9,"t":"형제 사랑에 관하여는 너희에게 쓸 것이 없음은 너희가 친히 하나님의 가르치심을 받아 서로 사랑함이라"},{"n":10,"t":"너희가 온 마게도냐 모든 형제를 대하여 과연 이것을 행하도다 형제들아 권하노니 더 많이 하고"},{"n":11,"t":"또 너희에게 명한 것 같이 종용하여 자기 일을 하고 너희 손으로 일하기를 힘쓰라"},{"n":12,"t":"이는 외인을 대하여 단정히 행하고 또한 아무 궁핍함이 없게 하려 함이라"},{"n":13,"t":"형제들아 자는 자들에 관하여는 너희가 알지 못함을 우리가 원치 아니하노니 이는 소망 없는 다른 이와 같이 슬퍼하지 않게 하려 함이라"},{"n":14,"t":"우리가 예수의 죽었다가 다시 사심을 믿을진대 이와 같이 예수 안에서 자는 자들도 하나님이 저와 함께 데리고 오시리라"},{"n":15,"t":"우리가 주의 말씀으로 너희에게 이것을 말하노니 주 강림하실 때까지 우리 살아 남아 있는 자도 자는 자보다 결단코 앞서지 못하리라"},{"n":16,"t":"주께서 호령과 천사장의 소리와 하나님의 나팔로 친히 하늘로 좇아 강림하시리니 그리스도 안에서 죽은 자들이 먼저 일어나고"},{"n":17,"t":"그 후에 우리 살아 남은 자도 저희와 함께 구름 속으로 끌어올려 공중에서 주를 영접하게 하시리니 그리하여 우리가 항상 주와 함께 있으리라"},{"n":18,"t":"그러므로 이 여러 말로 서로 위로하라"}],"kids":[]}},{"chapter":5,"title":"성결한 삶의 권면","verses":{"krv":[{"n":1,"t":"형제들아 때와 시기에 관하여는 너희에게 쓸 것이 없음은"},{"n":2,"t":"주의 날이 밤에 도적 같이 이를 줄을 너희 자신이 자세히 앎이라"},{"n":3,"t":"저희가 평안하다, 안전하다 할 그 때에 잉태된 여자에게 해산 고통이 이름과 같이 멸망이 홀연히 저희에게 이르리니 결단코 피하지 못하리라"},{"n":4,"t":"형제들아 너희는 어두움에 있지 아니하매 그 날이 도적 같이 너희에게 임하지 못하리니"},{"n":5,"t":"너희는 다 빛의 아들이요 낮의 아들이라 우리가 밤이나 어두움에 속하지 아니하나니"},{"n":6,"t":"그러므로 우리는 다른 이들과 같이 자지 말고 오직 깨어 근신할지라"},{"n":7,"t":"자는 자들은 밤에 자고 취하는 자들은 밤에 취하되"},{"n":8,"t":"우리는 낮에 속하였으니 근신하여 믿음과 사랑의 흉배를 붙이고 구원의 소망의 투구를 쓰자"},{"n":9,"t":"하나님이 우리를 세우심은 노하심에 이르게 하심이 아니요 오직 우리 주 예수 그리스도로 말미암아 구원을 얻게 하신 것이라"},{"n":10,"t":"예수께서 우리를 위하여 죽으사 우리로 하여금 깨든지 자든지 자기와 함께 살게 하려 하셨느니라"},{"n":11,"t":"그러므로 피차 권면하고 피차 덕을 세우기를 너희가 하는 것 같이 하라"},{"n":12,"t":"형제들아 우리가 너희에게 구하노니 너희 가운데서 수고하고 주 안에서 너희를 다스리며 권하는 자들을 너희가 알고"},{"n":13,"t":"저의 역사로 말미암아 사랑 안에서 가장 귀히 여기며 너희끼리 화목하라"},{"n":14,"t":"또 형제들아 너희를 권면하노니 규모 없는 자들을 권계하며 마음이 약한 자들을 안위하고 힘이 없는 자들을 붙들어 주며 모든 사람을 대하여 오래 참으라"},{"n":15,"t":"삼가 누가 누구에게든지 악으로 악을 갚지 말게 하고 오직 피차 대하든지 모든 사람을 대하든지 항상 선을 좇으라"},{"n":16,"t":"항상 기뻐하라"},{"n":17,"t":"쉬지 말고 기도하라"},{"n":18,"t":"범사에 감사하라 이는 그리스도 예수 안에서 너희를 향하신 하나님의 뜻이니라"},{"n":19,"t":"성령을 소멸치 말며"},{"n":20,"t":"예언을 멸시치 말고"},{"n":21,"t":"범사에 헤아려 좋은 것을 취하고"},{"n":22,"t":"악은 모든 모양이라도 버리라"},{"n":23,"t":"평강의 하나님이 친히 너희로 온전히 거룩하게 하시고 또 너희 온 영과 혼과 몸이 우리 주 예수 그리스도 강림하실 때에 흠 없게 보전되기를 원하노라"},{"n":24,"t":"너희를 부르시는 이는 미쁘시니 그가 또한 이루시리라"},{"n":25,"t":"형제들아 우리를 위하여 기도하라"},{"n":26,"t":"거룩하게 입맞춤으로 모든 형제에게 문안하라"},{"n":27,"t":"내가 주를 힘입어 너희를 명하노니 모든 형제에게 이 편지를 읽어 들리라"},{"n":28,"t":"우리 주 예수 그리스도의 은혜가 너희에게 있을지어다"}],"kids":[]}}]}');

